parameters.jsCode:
const item = $input.item;
const sessionId = $('Prepare Input').item.json.sessionId || '';
const allowedTools = Array.isArray(item.json.allowedTools) ? [...item.json.allowedTools] : item.json.allowedTools;

if (!Array.isArray(allowedTools)) {
  return item;
}

if (!sessionId.startsWith('telegram:')) {
  // Filter by tool IDs (what trace_prep returns), not display names
  const restricted = new Set(['telegram_send', 'telegram_hitl']);
  item.json.allowedTools = allowedTools.filter((tool) => {
    const id = typeof tool === 'string' ? tool : (tool?.id || tool?.name || '');
    return !restricted.has(id);
  });
}

return item;

// Log guardrail violations if detected
const item = $input.item;
const guardrailResult = item.json;

// Check if guardrails detected violations
if (guardrailResult.violations && guardrailResult.violations.length > 0) {
  // Store violation in memory via HTTP request (will be handled by error workflow if this fails)
  const violationData = {
    tool: 'memory_store',
    arguments: {
      content: `Guardrail violation detected: ${guardrailResult.violations.map(v => v.type).join(', ')}` ,
      memoryType: 'episodic',
      tags: ['security', 'guardrail-violation'],
      metadata: {
        traceId: item.json.traceId,
        violationTypes: guardrailResult.violations.map(v => v.type),
        originalInstructions: item.json.instructions,
        sanitizedInstructions: guardrailResult.sanitized || item.json.instructions
      }
    }
  };

  // Store violation data for later logging
  item.json.guardrailViolations = guardrailResult.violations;
  item.json.violationData = violationData;
}

return item;
